CODE_EXAMPLE:
// Before
class Employee {
  private String id;
  void setId(String id) { this.id = id; }
}

// After
class Employee {
  private final String id;
  Employee(String id) { this.id = id; }
}

UNIT_TEST_EXAMPLE:
@Test
public void testRemoveSetter() {
  Employee employee = new Employee("E123");
  assertEquals("E123", employee.getId());
